import{_ as a,o as c,c as o,a3 as t}from"./chunks/framework.aYYe0dfI.js";const u=JSON.parse('{"title":"Namespace clore::generate::cache","description":"The clore::generate::cache namespace provides a caching subsystem for generated content, storing prompt–response pairs to avoid redundant computation. Its core operations include find_cached_response, which performs a read-only lookup in a CacheIndex to retrieve a previously cached response, and save_cache_entry, which persists a new entry synchronously. Asynchronous variants (load_cache_index_async, save_cache_entry_async) use a kota::event_loop for non‑blocking I/O, while normalize_text_for_hashing and make_prompt_response_cache_key ensure deterministic, hash‑based keys for cache entries.","frontmatter":{"title":"Namespace clore::generate::cache","description":"The clore::generate::cache namespace provides a caching subsystem for generated content, storing prompt–response pairs to avoid redundant computation. Its core operations include find_cached_response, which performs a read-only lookup in a CacheIndex to retrieve a previously cached response, and save_cache_entry, which persists a new entry synchronously. Asynchronous variants (load_cache_index_async, save_cache_entry_async) use a kota::event_loop for non‑blocking I/O, while normalize_text_for_hashing and make_prompt_response_cache_key ensure deterministic, hash‑based keys for cache entries.","layout":"doc","template":"doc"},"headers":[],"relativePath":"clore/namespaces/clore/generate/cache/index.md","filePath":"en/clore/namespaces/clore/generate/cache/index.md"}'),n={name:"clore/namespaces/clore/generate/cache/index.md"};function r(s,e,i,d,h,l){return c(),o("div",null,[...e[0]||(e[0]=[t('<h1 id="namespace-clore-generate-cache" tabindex="-1">Namespace <code>clore::generate::cache</code> <a class="header-anchor" href="#namespace-clore-generate-cache" aria-label="Permalink to &quot;Namespace `clore::generate::cache`&quot;">​</a></h1><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>The <code>clore::generate::cache</code> namespace provides a caching subsystem for generated content, storing prompt–response pairs to avoid redundant computation. Its core operations include <code>find_cached_response</code>, which performs a read-only lookup in a <code>CacheIndex</code> to retrieve a previously cached response, and <code>save_cache_entry</code>, which persists a new entry synchronously. Asynchronous variants (<code>load_cache_index_async</code>, <code>save_cache_entry_async</code>) use a <code>kota::event_loop</code> for non‑blocking I/O, while <code>normalize_text_for_hashing</code> and <code>make_prompt_response_cache_key</code> ensure deterministic, hash‑based keys for cache entries.</p><p>The namespace uses <code>CacheIndex</code> and <code>CacheError</code> types to manage index data and report failures. It relies on a <code>workspace_root</code> to locate cache files and includes a mutex (<code>cache_file_mutex</code>) for thread‑safe access. Architecturally, this namespace sits between the generation pipeline and the file system, offering both synchronous and asynchronous cache operations that improve performance by reducing repeated identical requests.</p><h2 id="types" tabindex="-1">Types <a class="header-anchor" href="#types" aria-label="Permalink to &quot;Types&quot;">​</a></h2><h3 id="clore-generate-cache-cacheerror" tabindex="-1"><code>clore::generate::cache::CacheError</code> <a class="header-anchor" href="#clore-generate-cache-cacheerror" aria-label="Permalink to &quot;`clore::generate::cache::CacheError`&quot;">​</a></h3><p>Declaration: <code>generate/cache.cppm:16</code></p><p>Definition: <code>generate/cache.cppm:16</code></p><p>Implementation: <a href="./../../../../modules/generate/cache"><code>Module generate:cache</code></a></p><p>Insufficient evidence to summarize; provide more EVIDENCE.</p><h4 id="invariants" tabindex="-1">Invariants <a class="header-anchor" href="#invariants" aria-label="Permalink to &quot;Invariants&quot;">​</a></h4><ul><li><code>message</code> is a valid <code>std::string</code> (may be empty if no error details are provided)</li></ul><h4 id="key-members" tabindex="-1">Key Members <a class="header-anchor" href="#key-members" aria-label="Permalink to &quot;Key Members&quot;">​</a></h4><ul><li><code>message</code></li></ul><h4 id="usage-patterns" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Returned or thrown to indicate cache operation failures</li><li>Inspected by callers to retrieve error details</li></ul><h3 id="clore-generate-cache-cacheindex" tabindex="-1"><code>clore::generate::cache::CacheIndex</code> <a class="header-anchor" href="#clore-generate-cache-cacheindex" aria-label="Permalink to &quot;`clore::generate::cache::CacheIndex`&quot;">​</a></h3><p>Declaration: <code>generate/cache.cppm:20</code></p><p>Definition: <code>generate/cache.cppm:20</code></p><p>Implementation: <a href="./../../../../modules/generate/cache"><code>Module generate:cache</code></a></p><p>Insufficient evidence to summarize; provide more EVIDENCE.</p><h4 id="invariants-1" tabindex="-1">Invariants <a class="header-anchor" href="#invariants-1" aria-label="Permalink to &quot;Invariants&quot;">​</a></h4><ul><li>The map is unordered; iteration order is unspecified.</li><li>Keys and values are strings.</li></ul><h4 id="key-members-1" tabindex="-1">Key Members <a class="header-anchor" href="#key-members-1" aria-label="Permalink to &quot;Key Members&quot;">​</a></h4><ul><li><code>entries</code></li></ul><h4 id="usage-patterns-1" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-1" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Used as a lightweight index for caching or lookup purposes.</li></ul><h2 id="functions" tabindex="-1">Functions <a class="header-anchor" href="#functions" aria-label="Permalink to &quot;Functions&quot;">​</a></h2><h3 id="clore-generate-cache-find-cached-response" tabindex="-1"><code>clore::generate::cache::find_cached_response</code> <a class="header-anchor" href="#clore-generate-cache-find-cached-response" aria-label="Permalink to &quot;`clore::generate::cache::find_cached_response`&quot;">​</a></h3><p>Declaration: <code>generate/cache.cppm:35</code></p><p>Definition: <code>generate/cache.cppm:347</code></p><p>Implementation: <a href="./../../../../modules/generate/cache"><code>Module generate:cache</code></a></p><p>The function <code>clore::generate::cache::find_cached_response</code> performs a lookup in the provided <code>CacheIndex</code> using the given key, returning the cached response as a <code>std::optional&lt;std::string_view&gt;</code> if present. The caller is responsible for ensuring the <code>CacheIndex</code> is valid and the key corresponds to an entry previously stored via a save function (such as <code>clore::generate::cache::save_cache_entry</code>). If no matching entry exists, the function returns <code>std::nullopt</code>. The function does not modify the cache index and is safe to call concurrently with read-only access.</p><h4 id="usage-patterns-2" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-2" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Check existence of cached response before generation</li><li>Retrieve cached response by key from index</li></ul><h3 id="clore-generate-cache-load-cache-index" tabindex="-1"><code>clore::generate::cache::load_cache_index</code> <a class="header-anchor" href="#clore-generate-cache-load-cache-index" aria-label="Permalink to &quot;`clore::generate::cache::load_cache_index`&quot;">​</a></h3><p>Declaration: <code>generate/cache.cppm:29</code></p><p>Definition: <code>generate/cache.cppm:252</code></p><p>Implementation: <a href="./../../../../modules/generate/cache"><code>Module generate:cache</code></a></p><p>Loads the cache index from the location identified by the provided <code>std::string_view</code>. Returns a <code>std::expected&lt;CacheIndex, CacheError&gt;</code>; on success the caller receives a valid <code>CacheIndex</code> that can be passed to functions such as <code>clore::generate::cache::find_cached_response</code>. On failure a <code>CacheError</code> is returned indicating the reason the index could not be loaded.</p><h4 id="usage-patterns-3" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-3" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>called to load cache index from disk</li><li>used at initialization to populate in-memory cache index</li></ul><h3 id="clore-generate-cache-load-cache-index-async" tabindex="-1"><code>clore::generate::cache::load_cache_index_async</code> <a class="header-anchor" href="#clore-generate-cache-load-cache-index-async" aria-label="Permalink to &quot;`clore::generate::cache::load_cache_index_async`&quot;">​</a></h3><p>Declaration: <code>generate/cache.cppm:38</code></p><p>Definition: <code>generate/cache.cppm:356</code></p><p>Implementation: <a href="./../../../../modules/generate/cache"><code>Module generate:cache</code></a></p><p><code>clore::generate::cache::load_cache_index_async</code> initiates an asynchronous load of the cache index from a given file path. The caller provides a <code>std::string</code> specifying the location of the index file and a reference to a <code>kota::event_loop</code> on which the operation will be scheduled. The function returns an <code>int</code> that identifies the pending asynchronous load request, allowing the caller to correlate with the eventual completion notification. The caller must ensure that the provided <code>kota::event_loop</code> remains alive until the asynchronous operation finishes.</p><h4 id="usage-patterns-4" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-4" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>asynchronous loading of cache index</li><li>wrapping synchronous <code>load_cache_index</code> into a coroutine</li></ul><h3 id="clore-generate-cache-make-prompt-response-cache-key" tabindex="-1"><code>clore::generate::cache::make_prompt_response_cache_key</code> <a class="header-anchor" href="#clore-generate-cache-make-prompt-response-cache-key" aria-label="Permalink to &quot;`clore::generate::cache::make_prompt_response_cache_key`&quot;">​</a></h3><p>Declaration: <code>generate/cache.cppm:24</code></p><p>Definition: <code>generate/cache.cppm:219</code></p><p>Implementation: <a href="./../../../../modules/generate/cache"><code>Module generate:cache</code></a></p><p>The function <code>clore::generate::cache::make_prompt_response_cache_key</code> constructs a deterministic cache key from a prompt, a response, and an integer parameter. Callers provide the prompt text as a <code>std::string_view</code>, the response text as a <code>std::string_view</code>, and a version or configuration identifier as a <code>const int &amp;</code>. On success, the function returns a <code>std::expected&lt;std::string, CacheError&gt;</code> containing the hashed key string; on failure, it returns a <code>CacheError</code> indicating why key generation could not be completed.</p><p>The resulting key is intended for use with other cache operations such as <code>clore::generate::cache::find_cached_response</code> and <code>clore::generate::cache::save_cache_entry</code>. The function relies on <code>clore::generate::cache::normalize_text_for_hashing</code> to normalize both input texts before combining them, ensuring consistency across different representations of the same content.</p><h4 id="usage-patterns-5" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-5" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Used by <code>find_cached_response</code> and <code>save_cache_entry</code> to generate a unique key for cache operations.</li></ul><h3 id="clore-generate-cache-normalize-text-for-hashing" tabindex="-1"><code>clore::generate::cache::normalize_text_for_hashing</code> <a class="header-anchor" href="#clore-generate-cache-normalize-text-for-hashing" aria-label="Permalink to &quot;`clore::generate::cache::normalize_text_for_hashing`&quot;">​</a></h3><p>Declaration: <code>generate/cache.cppm:192</code></p><p>Definition: <code>generate/cache.cppm:192</code></p><p>Implementation: <a href="./../../../../modules/generate/cache"><code>Module generate:cache</code></a></p><p>Declaration: <a href="./functions/normalize-text-for-hashing">Declaration</a></p><p>Normalizes a given input text so that functionally equivalent strings produce an identical result, enabling consistent hashing within the caching system. The caller supplies a <code>std::string_view</code> and receives a <code>std::string</code> that has been transformed according to internal rules (for example, trimming whitespace and reducing letter case) to eliminate benign variations. This normalized string is intended to be used as part of a cache key, ensuring that the same conceptual prompt or system prompt always maps to the same hash regardless of incidental formatting differences.</p><h4 id="usage-patterns-6" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-6" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>called by <code>make_prompt_response_cache_key</code> to normalize prompt and response text before deriving a cache key</li></ul><h3 id="clore-generate-cache-save-cache-entry" tabindex="-1"><code>clore::generate::cache::save_cache_entry</code> <a class="header-anchor" href="#clore-generate-cache-save-cache-entry" aria-label="Permalink to &quot;`clore::generate::cache::save_cache_entry`&quot;">​</a></h3><p>Declaration: <code>generate/cache.cppm:31</code></p><p>Definition: <code>generate/cache.cppm:303</code></p><p>Implementation: <a href="./../../../../modules/generate/cache"><code>Module generate:cache</code></a></p><p>The function <code>clore::generate::cache::save_cache_entry</code> persists a prompt–response pair into the cache storage. It accepts three <code>std::string_view</code> arguments, which correspond to a cache key (derived from the prompt), the prompt text, and the associated response text. On success the function returns <code>std::expected&lt;void, CacheError&gt;</code> with an empty value; on failure it returns a <code>CacheError</code> indicating the reason for the failure. Callers must ensure that the provided strings remain valid for the duration of the call, and that the cache storage is accessible and writable.</p><h4 id="usage-patterns-7" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-7" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>called to persist a generated response to the cache</li><li>used after a successful generation to update the cache</li><li>likely invoked synchronously from a code path that just produced a response</li></ul><h3 id="clore-generate-cache-save-cache-entry-async" tabindex="-1"><code>clore::generate::cache::save_cache_entry_async</code> <a class="header-anchor" href="#clore-generate-cache-save-cache-entry-async" aria-label="Permalink to &quot;`clore::generate::cache::save_cache_entry_async`&quot;">​</a></h3><p>Declaration: <code>generate/cache.cppm:41</code></p><p>Definition: <code>generate/cache.cppm:376</code></p><p>Implementation: <a href="./../../../../modules/generate/cache"><code>Module generate:cache</code></a></p><p>The function <code>clore::generate::cache::save_cache_entry_async</code> initiates an asynchronous save of a cache entry. The caller provides three <code>std::string</code> arguments—typically representing the cache key, the value to store, and an additional identifier such as a model or hash string—along with a <code>kota::event_loop &amp;</code> on which the completion will be delivered. It returns an <code>int</code> that signals whether the operation was successfully enqueued; the caller must ensure the given event loop remains active until the save completes.</p><h4 id="usage-patterns-8" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-8" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Called to asynchronously persist a generated response to the cache</li></ul><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./../">Namespace clore::generate</a></li></ul>',81)])])}const g=a(n,[["render",r]]);export{u as __pageData,g as default};
